import React from "react";

const About = () => {
  return (
    <section className="py-20 bg-slate-50 px-6 border-t border-slate-200">
      <div className="max-w-4xl mx-auto text-center">
        <h2 className="text-3xl font-bold mb-6 text-slate-900">
          Backed by KaroStartup
        </h2>
        <p className="text-lg text-slate-700 leading-relaxed">
          Over the past 5 years, KaroStartup has built one of India’s largest
          startup storytelling platforms, sharing thousands of founder journeys
          and inspiring a massive community of entrepreneurs across the country.
          Karo Pitch is our next step in actively funding the ecosystem.
        </p>
      </div>
    </section>
  );
};

export default About;
